import sys
from math import gcd

input = sys.stdin.readline

def solve():
    n = int(input())
    a = list(map(int, input().split()))
    if n == 1:
        print(1)
        return

    diffs = [abs(a[i+1] - a[i]) for i in range(n-1)]

    best = 1
    # For each position, track (gcd_value, start_index) pairs
    prev = []  # list of (gcd, leftmost_start)

    for i, d in enumerate(diffs):
        curr = []
        for g, start in prev:
            ng = gcd(g, d)
            if curr and curr[-1][0] == ng:
                pass  # same gcd, keep earlier start
            else:
                curr.append((ng, start))
        if not curr or curr[-1][0] != d:
            curr.append((d, i))

        for g, start in curr:
            if g >= 2:
                best = max(best, i - start + 2)

        prev = curr

    print(best)

t = int(input())
for _ in range(t):
    solve()

